patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9df08553d86e..75c69c2a299d 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8790,6 +8790,85 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
     }
   }

+  // fcmp (fptrunc X), C -> fcmp X, threshold
+  // The threshold depends on the predicate:
+  // - OGE/UGE: X >= threshold where threshold = midpoint(C, prev(C))
+  // - OGT/UGT: X > threshold where threshold = midpoint(C, next(C))
+  // - OLE/ULE: X <= threshold where threshold = midpoint(C, next(C))  
+  // - OLT/ULT: X < threshold where threshold = midpoint(C, prev(C))
+  if (match(Op0, m_FPTrunc(m_Value(X)))) {
+    const APFloat *C;
+    if (match(Op1, m_APFloat(C))) {
+      Type *SrcTy = X->getType()->getScalarType();
+      Type *DstTy = Op0->getType()->getScalarType();
+      // Only handle cases where we're truncating to a smaller type
+      if (SrcTy->getFPMantissaWidth() > DstTy->getFPMantissaWidth()) {
+        const fltSemantics &SrcSem = SrcTy->getFltSemantics();
+        const fltSemantics &DstSem = DstTy->getFltSemantics();
+        APFloat CFloat = *C;
+        bool Ignored;
+        CFloat.convert(DstSem, APFloat::rmNearestTiesToEven, &Ignored);
+        
+        // Determine which midpoint to use based on predicate
+        bool UseNext = false;
+        bool ValidPredicate = false;
+        
+        switch (Pred) {
+        case FCmpInst::FCMP_OLE:
+        case FCmpInst::FCMP_ULE:
+          UseNext = true;
+          ValidPredicate = true;
+          break;
+        case FCmpInst::FCMP_OGE:
+        case FCmpInst::FCMP_UGE:
+        case FCmpInst::FCMP_OLT:
+        case FCmpInst::FCMP_ULT:
+          UseNext = false;
+          ValidPredicate = true;
+          break;
+        case FCmpInst::FCMP_OGT:
+        case FCmpInst::FCMP_UGT:
+          UseNext = true;
+          ValidPredicate = true;
+          break;
+        default:
+          break;
+        }
+        
+        if (!ValidPredicate)
+          return nullptr;
+        
+        APFloat NeighborC = CFloat;
+        APFloat::opStatus Status = UseNext ? NeighborC.next(false) : NeighborC.next(true);
+        if (Status != APFloat::opOK)
+          return nullptr;
+        
+        // Compute midpoint in source type to preserve precision for all FP types
+        // Convert both CFloat and NeighborC to source type first
+        APFloat CInSrc = CFloat;
+        CInSrc.convert(SrcSem, APFloat::rmNearestTiesToEven, &Ignored);
+        APFloat NeighborInSrc = NeighborC;
+        NeighborInSrc.convert(SrcSem, APFloat::rmNearestTiesToEven, &Ignored);
+        
+        // Midpoint = (CInSrc + NeighborInSrc) / 2
+        APFloat Threshold = CInSrc;
+        Status = Threshold.add(NeighborInSrc, APFloat::rmNearestTiesToEven);
+        if (Status != APFloat::opOK)
+          return nullptr;
+        
+        APFloat Two(SrcSem, 2);
+        Status = Threshold.divide(Two, APFloat::rmNearestTiesToEven);
+        if (Status != APFloat::opOK)
+          return nullptr;
+        
+        Constant *NewC = ConstantFP::get(X->getType(), Threshold);
+        FCmpInst *Result = new FCmpInst(Pred, X, NewC, "", &I);
+        Result->copyFastMathFlags(&I);
+        return Result;
+      }
+    }
+  }
+
   // Convert a sign-bit test of an FP value into a cast and integer compare.
   // TODO: Simplify if the copysign constant is 0.0 or NaN.
   // TODO: Handle non-zero compare constants.

